using Microsoft.EntityFrameworkCore;

class CosmosDbContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // EF Core 9 breaking change: the Cosmos provider now writes "$type"
        // instead of "Discriminator" by default. Existing documents still use
        // "Discriminator", so we must preserve the old property name.
        modelBuilder.Entity<Product>(b =>
        {
            b.ToContainer("Products");
            b.HasDiscriminator<string>("Discriminator");
        });
    }
}

class Product
{
    public string Id { get; set; } = default!;
    public string Name { get; set; } = default!;
}

using Microsoft.EntityFrameworkCore;

class CosmosQueryService
{
    // EF Core 9 breaking change: the Cosmos provider no longer supports
    // synchronous I/O. All queries must use async methods.

    // BEFORE (EF Core 8 — sync, now throws InvalidOperationException):
    //   var products = db.Products.ToList();
    //   var first    = db.Products.First();
    //   var count    = db.Products.Count();

    // AFTER (EF Core 9 — async):
    async Task<List<Product>> GetAllProductsAsync(CosmosDbContext db)
    {
        return await db.Products.ToListAsync();
    }

    async Task<Product> GetFirstProductAsync(CosmosDbContext db)
    {
        return await db.Products.FirstAsync();
    }

    async Task<int> CountProductsAsync(CosmosDbContext db)
    {
        return await db.Products.CountAsync();
    }
}

